#!/usr/bin/env node
import {
  copyFile,
  mkdir,
  readdir,
  rm,
  rmdir,
  writeFile,
} from "node:fs/promises";
import path from "node:path";
import process from "node:process";
import { fileURLToPath } from "node:url";

import {
  BUNDLE_PATHS,
  inspectSourceBundle,
  stableJson,
} from "./lib/plugin-bundle.mjs";

const scriptRoot = path.dirname(fileURLToPath(import.meta.url));
const repositoryRoot = path.resolve(scriptRoot, "..");
const resourcesRoot = path.resolve(
  repositoryRoot,
  "installer/src-tauri/resources",
);
const bundleRoot = path.join(resourcesRoot, "plugin-bundle");
const metadataPath = path.join(resourcesRoot, "plugin-bundle-files.json");
const markerPath = path.join(resourcesRoot, ".plugin-bundle-generated");

async function removePreviousGeneratedFiles() {
  for (const relativePath of BUNDLE_PATHS) {
    await rm(path.join(bundleRoot, ...relativePath.split("/")), {
      force: true,
    });
  }
  const directories = new Set(
    BUNDLE_PATHS.flatMap((relativePath) => {
      const parts = relativePath.split("/").slice(0, -1);
      return parts.map((_, index) => parts.slice(0, index + 1).join("/"));
    }),
  );
  for (const relativeDirectory of [...directories].sort(
    (a, b) => b.length - a.length,
  )) {
    const absoluteDirectory = path.join(
      bundleRoot,
      ...relativeDirectory.split("/"),
    );
    try {
      if ((await readdir(absoluteDirectory)).length === 0)
        await rmdir(absoluteDirectory);
    } catch (error) {
      if (error?.code !== "ENOENT") throw error;
    }
  }
}

const inspected = await inspectSourceBundle(repositoryRoot);
await mkdir(resourcesRoot, { recursive: true });
await removePreviousGeneratedFiles();
for (const file of inspected.files) {
  const destination = path.join(bundleRoot, ...file.path.split("/"));
  await mkdir(path.dirname(destination), { recursive: true, mode: 0o700 });
  await copyFile(file.absolutePath, destination);
}
await writeFile(metadataPath, stableJson(inspected.metadata), {
  encoding: "utf8",
  mode: 0o600,
});
await writeFile(markerPath, "Generated by scripts/build-plugin-bundle.mjs\n", {
  encoding: "utf8",
  mode: 0o600,
});

console.log(
  `Plugin bundle ${inspected.metadata.plugin_version}: ${inspected.metadata.plugin_bundle_sha256}`,
);
console.log(
  `Files: ${inspected.metadata.files.length}; metadata: ${path.relative(repositoryRoot, metadataPath)}`,
);
